      "path": "CoEAdoptionMaturity.SemanticModel/definition/tables/Maturity Assessment.tmdl",
      "content": "table 'Maturity Assessment'\n\tlineageTag: 77968aaf-d937-74f5-d67b-b08d6416a71c\n\n\t/// Mean current maturity (1–5) across assessed capabilities.\n\tmeasure 'Avg Maturity' = AVERAGE('Maturity Assessment'[CurrentLevel])\n\t\tformatString: 0.0\n\t\tlineageTag: 0eded2b8-3af7-9804-853e-57c672c78d3e\n\n\tmeasure 'Target Gap' = AVERAGE('Maturity Assessment'[TargetLevel]) - AVERAGE('Maturity Assessment'[CurrentLevel])\n\t\tformatString: 0.0\n\t\tlineageTag: 308941be-399f-e2f2-6718-a24852e32484\n\n\tmeasure 'Adoption %' = DIVIDE(SUM('Maturity Assessment'[CurrentLevel]), SUM('Maturity Assessment'[TargetLevel]))\n\t\tformatString: 0.0%\n\t\tlineageTag: 7da863b0-2ae2-7638-e779-5700c1e6c932\n\n\tmeasure 'Capabilities Assessed' = COUNTROWS('Maturity Assessment')\n\t\tformatString: #,##0\n\t\tlineageTag: cc4fd812-2757-dc6c-efe7-1ab7e14b0890\n\n\tcolumn 'Pillar'\n\t\tdataType: string\n\t\tlineageTag: 457e6f82-4603-ae5d-d002-6c6fce082e80\n\t\tsummarizeBy: none\n\t\tsourceColumn: Pillar\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tcolumn 'Capability'\n\t\tdataType: string\n\t\tlineageTag: 40f0d848-9ca9-da8a-02d3-dec3fe75141d\n\t\tsummarizeBy: none\n\t\tsourceColumn: Capability\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tcolumn 'CurrentLevel'\n\t\tdataType: int64\n\t\tlineageTag: 344c6b1a-a3d5-3fff-4792-514146330a13\n\t\tsummarizeBy: average\n\t\tsourceColumn: CurrentLevel\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tcolumn 'TargetLevel'\n\t\tdataType: int64\n\t\tlineageTag: 13108fb5-30d0-be88-69ff-4d8c7dcadee7\n\t\tsummarizeBy: average\n\t\tsourceColumn: TargetLevel\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tcolumn 'Owner'\n\t\tdataType: string\n\t\tlineageTag: 4217f0af-389c-ea1a-9fbf-21d8f216f658\n\t\tsummarizeBy: none\n\t\tsourceColumn: Owner\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tcolumn 'AssessedDate'\n\t\tdataType: dateTime\n\t\tformatString: General Date\n\t\tlineageTag: 48f8184c-79ba-ec2b-82f9-1263cb2e5d49\n\t\tsummarizeBy: none\n\t\tsourceColumn: AssessedDate\n\n\t\tannotation SummarizationSetBy = Automatic\n\n\tpartition 'Maturity Assessment' = m\n\t\tmode: import\n\t\tsource =\n\t\t\t\tlet\n\t\t\t\t\t// SAMPLE DATA — replace the \"Source\" step below with the live Azure query.\n\t\t\t\t\t// === Live source (uncomment + remove the sample step) ===\n\t\t\t\t\t// // CoE-maintained scorecard. Common sources: a SharePoint list, Dataverse table,\n\t\t\t\t\t// // or a Loom governance Cosmos container. Example (SharePoint):\n\t\t\t\t\t// // Source = SharePoint.Tables(\"https://contoso.sharepoint.com/sites/CoE\"){[Title=\"Maturity\"]}[Items]\n\t\t\t\t\t// === end live source ===\n\t\t\t\t\tSource = #table(\n\t\t\t\t\t\ttype table [#\"Pillar\"=type text, #\"Capability\"=type text, #\"CurrentLevel\"=Int64.Type, #\"TargetLevel\"=Int64.Type, #\"Owner\"=type text, #\"AssessedDate\"=type datetime],\n\t\t\t\t\t\t{\n\t\t\t\t\t\t\t{\"Strategy & Governance\", \"Cloud operating model\", 3, 5, \"CoE Lead\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Strategy & Governance\", \"Policy as code\", 2, 4, \"Governance\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Security\", \"Zero Trust identity\", 3, 5, \"Security\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Security\", \"Workload protection\", 2, 4, \"Security\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"FinOps\", \"Cost allocation & tagging\", 2, 5, \"FinOps\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Platform\", \"Landing zone conformance\", 4, 5, \"Platform\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Data\", \"Data governance & lineage\", 2, 4, \"Data\", #datetime(2026,3,1,0,0,0)},\n\t\t\t\t\t\t\t{\"Operations\", \"Observability & SLO\", 3, 5, \"SRE\", #datetime(2026,3,1,0,0,0)}\n\t\t\t\t\t\t}\n\t\t\t\t\t)\n\t\t\t\tin\n\t\t\t\t\tSource\n\n\tannotation PBI_ResultType = Table\n"
